#include <bits/stdc++.h>
using namespace std;
int board[10][11];
string s;
bool win(){
    for(int i = 0; i < 6; i++){
        for(int j = 0; j < 7; j++){
            if(board[i][j]){
                int c=1;
                //vertical
                for(int k = 1; k < 4; k++){
                    if(i+k<6&&board[i+k][j]==board[i][j])c++;
                    else break;
                }
                if(c>=4)return 1;
                c=1;
                //horizontal
                for(int k = 1; k < 4; k++){
                    if(j+k<7&&board[i][j+k]==board[i][j])c++;
                    else break;
                }
                if(c>=4)return 1;
                c=1;
                //diagonal down-right
                for(int k = 1; k < 4; k++){
                    if(i+k<6&&j+k<7&&board[i+k][j+k]==board[i][j])c++;
                    else break;
                }
                if(c>=4)return 1;
                c=1;
                //diagonal up-right
                for(int k = 1; k < 4; k++){
                    if(i-k>=0&&j+k<7&&board[i-k][j+k]==board[i][j])c++;
                    else break;
                }
                if(c>=4)return 1;
            }
        }
    }
    return 0;
}
signed main(){
    ios::sync_with_stdio(0);cin.tie(0);
    for(int i = 0; i < 6; i++){
        cin>>s;
        for(int j = 0; j < 7; j++){
            if(s[j]=='x')board[i][j]=1;
            else if(s[j]=='o')board[i][j]=-1;
            else board[i][j]=0;
        }
    }
    for(int i = 0; i < 7; i++){
        //find height of the column
        int h=5;
        while(h>=0&&board[h][i])h--;
        if(h<0)continue;
        //check if placing a piece in this column wins the game
        board[h][i]=1;
        if(win()){
            cout<<i;
            return 0;
        }
        board[h][i]=0;
    }
}
